import { sqliteTable, text, integer, index } from 'drizzle-orm/sqlite-core';
import { sql } from 'drizzle-orm';

// ── Status enums (stored as text in SQLite, validated by Zod at app layer) ──

export const milestoneStatusEnum = ['draft', 'in-progress', 'completed', 'archived'] as const;
export type MilestoneStatus = (typeof milestoneStatusEnum)[number];

export const moduleStatusEnum = ['draft', 'in-progress', 'completed'] as const;
export type ModuleStatus = (typeof moduleStatusEnum)[number];

export const taskStatusEnum = [
	'todo',
	'in-progress',
	'blocked',
	'review',
	'done',
	'skipped'
] as const;
export type TaskStatus = (typeof taskStatusEnum)[number];

// ── Milestone ────────────────────────────────────────────────────────────────
// Primary entity. ID format: MS-{seq} (e.g. MS-1, MS-2).

export const milestones = sqliteTable(
	'milestones',
	{
		id: text('id').primaryKey(), // MS-{seq}
		title: text('title').notNull(),
		sourceMd: text('source_md'),
		gitUrl: text('git_url'),
		status: text('status', { enum: milestoneStatusEnum }).notNull().default('draft'),
		createdAt: integer('created_at', { mode: 'timestamp' })
			.notNull()
			.default(sql`(unixepoch())`)
	},
	(table) => [index('milestone_status_idx').on(table.status)]
);

// ── Module ───────────────────────────────────────────────────────────────────
// Groups tasks within a milestone. ID format: MOD-{milestone_seq}-{seq}.

export const modules = sqliteTable(
	'modules',
	{
		id: text('id').primaryKey(), // MOD-{ms_seq}-{seq}
		milestoneId: text('milestone_id')
			.notNull()
			.references(() => milestones.id, { onDelete: 'cascade' }),
		name: text('name').notNull(),
		description: text('description'),
		status: text('status', { enum: moduleStatusEnum }).notNull().default('draft'),
		sortOrder: integer('sort_order').notNull().default(0)
	},
	(table) => [
		index('module_milestone_id_idx').on(table.milestoneId),
		index('module_status_idx').on(table.status)
	]
);

// ── Task ─────────────────────────────────────────────────────────────────────
// Atomic unit of work. ID format: TASK-{global_seq}.
// short_id is a global auto-increment for human-friendly references.

export const tasks = sqliteTable(
	'tasks',
	{
		id: text('id').primaryKey(), // TASK-{global_seq}
		shortId: integer('short_id').notNull().unique(), // global auto-increment
		moduleId: text('module_id')
			.notNull()
			.references(() => modules.id, { onDelete: 'cascade' }),
		title: text('title').notNull(),
		description: text('description'),
		references: text('references'), // JSON or text blob
		status: text('status', { enum: taskStatusEnum }).notNull().default('todo'),
		assignee: text('assignee'),
		subTotal: integer('sub_total').notNull().default(0),
		subDone: integer('sub_done').notNull().default(0),
		progressMessage: text('progress_message'),
		commitHash: text('commit_hash'),
		createdAt: integer('created_at', { mode: 'timestamp' })
			.notNull()
			.default(sql`(unixepoch())`),
		updatedAt: integer('updated_at', { mode: 'timestamp' })
			.notNull()
			.default(sql`(unixepoch())`),
		reportedAt: integer('reported_at', { mode: 'timestamp' })
	},
	(table) => [
		index('task_status_module_idx').on(table.status, table.moduleId),
		index('task_status_reported_idx').on(table.status, table.reportedAt),
		index('task_module_id_idx').on(table.moduleId),
		index('task_short_id_idx').on(table.shortId)
	]
);

// ── Type exports for use in application code ──

export type Milestone = typeof milestones.$inferSelect;
export type NewMilestone = typeof milestones.$inferInsert;
export type Module = typeof modules.$inferSelect;
export type NewModule = typeof modules.$inferInsert;
export type Task = typeof tasks.$inferSelect;
export type NewTask = typeof tasks.$inferInsert;

export { createMilestoneSchema, updateMilestoneSchema, milestoneResponseSchema } from './milestone.js';
export type { CreateMilestoneInput, UpdateMilestoneInput, MilestoneResponse } from './milestone.js';

export { createModuleSchema, updateModuleSchema, moduleResponseSchema } from './module.js';
export type { CreateModuleInput, UpdateModuleInput, ModuleResponse } from './module.js';

export {
	claimTaskSchema,
	progressTaskSchema,
	completeTaskSchema,
	adminTaskActionSchema,
	taskResponseSchema,
	isValidTransition
} from './task.js';
export type {
	ClaimTaskInput,
	ProgressTaskInput,
	CompleteTaskInput,
	AdminTaskActionInput,
	TaskResponse
} from './task.js';

export { loginRequestSchema, loginResponseSchema } from './auth.js';
export type { LoginRequest, LoginResponse } from './auth.js';

export {
	paginationQuerySchema,
	paginatedResponseSchema,
	errorResponseSchema,
	fieldErrorSchema,
	milestoneIdSchema,
	moduleIdSchema,
	taskIdSchema,
	sourceMdSchema,
	SOURCE_MD_MAX_BYTES
} from './common.js';
export type {
	PaginationQuery,
	ErrorResponse,
	FieldError
} from './common.js';

import { createHmac, randomBytes, timingSafeEqual } from 'node:crypto';

// ── Configuration ───────────────────────────────────────────────────────────

function getEnvOrThrow(key: string): string {
	const val = process.env[key];
	if (!val) throw new Error(`Missing required env var: ${key}`);
	return val;
}

/** Derive a signing secret from ADMIN_PASSWORD (always available in production). */
function getSigningSecret(): string {
	const pw = process.env.ADMIN_PASSWORD || '';
	// Use HMAC of a fixed salt with the password as key to derive a stable secret
	return createHmac('sha256', pw).update('milestone-tracker-session-salt').digest('hex');
}

/** Parse comma-separated API_KEYS from .env */
function getApiKeys(): string[] {
	const raw = process.env.API_KEYS || '';
	return raw
		.split(',')
		.map((k) => k.trim())
		.filter(Boolean);
}

// ── Session Management (stateless signed tokens) ────────────────────────────
// Token format: `{randomHex}.{hmac-sha256-hex}`
// This is stateless — no server-side session store needed.

const SESSION_COOKIE_NAME = 'mt_session';
const SESSION_MAX_AGE_MS = 24 * 60 * 60 * 1000; // 24 hours

export interface Session {
	token: string;
	signedToken: string;
	createdAt: number;
	maxAge: number;
}

/** Create a new signed session token. */
export function createSession(): Session {
	const token = randomBytes(32).toString('hex');
	const signature = createHmac('sha256', getSigningSecret()).update(token).digest('hex');
	const signedToken = `${token}.${signature}`;
	return {
		token,
		signedToken,
		createdAt: Date.now(),
		maxAge: SESSION_MAX_AGE_MS
	};
}

/** Verify a signed session token. Returns true if valid and not expired. */
export function verifySession(signedToken: string, maxAge: number = SESSION_MAX_AGE_MS): boolean {
	const lastDot = signedToken.lastIndexOf('.');
	if (lastDot === -1) return false;

	const token = signedToken.substring(0, lastDot);
	const providedSignature = signedToken.substring(lastDot + 1);

	if (!token || !providedSignature) return false;

	const expectedSignature = createHmac('sha256', getSigningSecret()).update(token).digest('hex');

	try {
		return timingSafeEqual(
			Buffer.from(providedSignature, 'hex'),
			Buffer.from(expectedSignature, 'hex')
		);
	} catch {
		return false;
	}
}

/** Destroy a session by returning a cookie that immediately expires. */
export function destroySessionCookie(): { name: string; value: string; options: SessionCookieOptions } {
	return {
		name: SESSION_COOKIE_NAME,
		value: '',
		options: {
			path: '/',
			httpOnly: true,
			secure: process.env.NODE_ENV === 'production',
			sameSite: 'lax',
			maxAge: 0
		}
	};
}

/** Build a Set-Cookie header value for a new session. */
export function buildSessionCookie(session: Session): string {
	const opts = sessionCookieOptions(session.maxAge);
	return `${SESSION_COOKIE_NAME}=${session.signedToken}; Path=${opts.path}; HttpOnly${opts.secure ? '; Secure' : ''}; SameSite=${opts.sameSite}; Max-Age=${Math.floor(opts.maxAge / 1000)}`;
}

// ── Bearer Token Validation ─────────────────────────────────────────────────

/** Validate a Bearer token against API_KEYS from .env. */
export function validateBearerToken(token: string): boolean {
	const apiKeys = getApiKeys();
	const tokenBuf = Buffer.from(token);
	return apiKeys.some((key) => {
		const keyBuf = Buffer.from(key);
		if (tokenBuf.length !== keyBuf.length) return false;
		return timingSafeEqual(tokenBuf, keyBuf);
	});
}

// ── Cookie Helpers ──────────────────────────────────────────────────────────

export interface SessionCookieOptions {
	path: string;
	httpOnly: boolean;
	secure: boolean;
	sameSite: 'lax' | 'strict';
	maxAge: number; // seconds
}

function sessionCookieOptions(maxAgeMs: number): SessionCookieOptions {
	return {
		path: '/',
		httpOnly: true,
		secure: process.env.NODE_ENV === 'production',
		sameSite: 'lax',
		maxAge: Math.floor(maxAgeMs / 1000)
	};
}

// ── Auth Middleware Logic ────────────────────────────────────────────────────
// Extracted as pure functions for testability. Used by hooks.server.ts.

export type AuthResult =
	| { authenticated: true; method: 'cookie' | 'bearer' }
	| { authenticated: false; reason: string };

/** Extract the signed session token from a Cookie header string. */
export function extractSessionCookie(cookieHeader: string | null): string | null {
	if (!cookieHeader) return null;
	const match = cookieHeader.match(/(?:^|;\s*)mt_session=([^;]+)/);
	return match ? match[1] : null;
}

/** Extract Bearer token from Authorization header. */
export function extractBearerToken(authHeader: string | null): string | null {
	if (!authHeader) return null;
	const parts = authHeader.split(' ');
	if (parts.length !== 2 || parts[0] !== 'Bearer') return null;
	return parts[1] || null;
}

/**
 * Check authentication from cookie and/or authorization headers.
 * Returns the auth result without performing any side effects.
 */
export function checkAuth(
	cookieHeader: string | null,
	authHeader: string | null
): AuthResult {
	// 1. Try Bearer token first (CLI/API usage)
	const bearer = extractBearerToken(authHeader);
	if (bearer) {
		if (validateBearerToken(bearer)) {
			return { authenticated: true, method: 'bearer' };
		}
		return { authenticated: false, reason: 'invalid_bearer_token' };
	}

	// 2. Try session cookie (Web usage)
	const sessionToken = extractSessionCookie(cookieHeader);
	if (sessionToken) {
		if (verifySession(sessionToken)) {
			return { authenticated: true, method: 'cookie' };
		}
		return { authenticated: false, reason: 'invalid_session' };
	}

	return { authenticated: false, reason: 'no_credentials' };
}

/** Validate a login password against ADMIN_PASSWORD env var. */
export function validatePassword(password: string): boolean {
	const adminPassword = process.env.ADMIN_PASSWORD;
	if (!adminPassword) return false;
	const pwBuf = Buffer.from(password);
	const adminBuf = Buffer.from(adminPassword);
	if (pwBuf.length !== adminBuf.length) return false;
	return timingSafeEqual(pwBuf, adminBuf);
}

// ── Exports for hooks ───────────────────────────────────────────────────────

export const AUTH_COOKIE_NAME = SESSION_COOKIE_NAME;

import { redirect, json } from '@sveltejs/kit';
import type { Handle } from '@sveltejs/kit';
import { checkAuth } from '$lib/server/auth.js';

export const handle: Handle = async ({ event, resolve }) => {
	const { url, request, cookies } = event;
	const path = url.pathname;

	// Skip auth for static assets and prerendered pages
	if (path.startsWith('/_app/') || path.startsWith('/favicon')) {
		return resolve(event);
	}

	// Public routes — no auth required
	const publicRoutes = ['/login', '/api/auth/login', '/api/auth/logout'];
	if (publicRoutes.some((r) => path === r || path.startsWith(r + '/'))) {
		// If already authenticated and visiting /login, redirect to home
		if (path === '/login') {
			const cookieHeader = request.headers.get('cookie');
			const authHeader = request.headers.get('authorization');
			const result = checkAuth(cookieHeader, authHeader);
			if (result.authenticated) {
				throw redirect(302, '/');
			}
		}
		return resolve(event);
	}

	// ── API routes: require auth (cookie or bearer) ──
	if (path.startsWith('/api/')) {
		const cookieHeader = request.headers.get('cookie');
		const authHeader = request.headers.get('authorization');
		const result = checkAuth(cookieHeader, authHeader);

		if (!result.authenticated) {
			// Return 401 JSON for API routes
			return json(
				{
					error: 'unauthorized',
					message: result.reason === 'invalid_bearer_token' ? '无效的 API Key' : '请先登录'
				},
				{ status: 401 }
			);
		}

		// Attach auth method to locals for downstream use
		event.locals.authMethod = result.method;
		return resolve(event);
	}

	// ── Page routes: require cookie auth, redirect to /login ──
	const cookieHeader = request.headers.get('cookie');
	const authHeader = request.headers.get('authorization');
	const result = checkAuth(cookieHeader, authHeader);

	if (!result.authenticated) {
		throw redirect(302, '/login');
	}

	event.locals.authMethod = result.method;
	return resolve(event);
};

import { json } from '@sveltejs/kit';
import type { RequestHandler } from './$types.js';
import { createSession, validatePassword, buildSessionCookie, AUTH_COOKIE_NAME } from '$lib/server/auth.js';
import { loginRequestSchema } from '$lib/schemas/auth.js';

export const POST: RequestHandler = async ({ request, cookies }) => {
	// 1. Parse and validate request body
	let body: unknown;
	try {
		body = await request.json();
	} catch {
		return json({ error: 'invalid_json', message: 'Request body must be valid JSON' }, { status: 400 });
	}

	const parsed = loginRequestSchema.safeParse(body);
	if (!parsed.success) {
		return json(
			{
				error: 'validation_error',
				message: 'Validation failed',
				details: parsed.error.issues.map((i) => ({
					field: i.path.join('.'),
					message: i.message
				}))
			},
			{ status: 400 }
		);
	}

	// 2. Validate password
	if (!validatePassword(parsed.data.password)) {
		return json({ error: 'unauthorized', message: '密码错误' }, { status: 401 });
	}

	// 3. Create session
	const session = createSession();

	// 4. Set HttpOnly session cookie
	cookies.set(AUTH_COOKIE_NAME, session.signedToken, {
		path: '/',
		httpOnly: true,
		secure: process.env.NODE_ENV === 'production',
		sameSite: 'lax',
		maxAge: Math.floor(session.maxAge / 1000)
	});

	// 5. Return success with token
	return json({ token: session.signedToken });
};

import { z } from 'zod';
import { milestoneStatusEnum } from '../db/schema.js';
import { sourceMdSchema, milestoneIdSchema } from './common.js';

// ── Create ──────────────────────────────────────────────────────────────────

export const createMilestoneSchema = z.object({
	title: z.string().min(1, 'Title is required').max(200, 'Title must be under 200 characters'),
	sourceMd: sourceMdSchema.optional(),
	gitUrl: z.string().url('Invalid URL').optional().or(z.literal(''))
});
export type CreateMilestoneInput = z.infer<typeof createMilestoneSchema>;

// ── Update ──────────────────────────────────────────────────────────────────

export const updateMilestoneSchema = z.object({
	title: z.string().min(1).max(200).optional(),
	sourceMd: sourceMdSchema.optional(),
	gitUrl: z.string().url().optional().or(z.literal('')),
	status: z.enum(milestoneStatusEnum).optional()
});
export type UpdateMilestoneInput = z.infer<typeof updateMilestoneSchema>;

// ── Response ────────────────────────────────────────────────────────────────

export const milestoneResponseSchema = z.object({
	id: milestoneIdSchema,
	title: z.string(),
	sourceMd: z.string().nullable(),
	gitUrl: z.string().nullable(),
	status: z.enum(milestoneStatusEnum),
	createdAt: z.string().datetime() // ISO 8601
});
export type MilestoneResponse = z.infer<typeof milestoneResponseSchema>;

import { z } from 'zod';
import { moduleStatusEnum } from '../db/schema.js';
import { moduleIdSchema, milestoneIdSchema } from './common.js';

// ── Create ──────────────────────────────────────────────────────────────────

export const createModuleSchema = z.object({
	milestoneId: milestoneIdSchema,
	name: z.string().min(1, 'Name is required').max(200, 'Name must be under 200 characters'),
	description: z.string().max(5000).optional(),
	sortOrder: z.number().int().nonnegative().default(0)
});
export type CreateModuleInput = z.infer<typeof createModuleSchema>;

// ── Update ──────────────────────────────────────────────────────────────────

export const updateModuleSchema = z.object({
	name: z.string().min(1).max(200).optional(),
	description: z.string().max(5000).optional(),
	status: z.enum(moduleStatusEnum).optional(),
	sortOrder: z.number().int().nonnegative().optional()
});
export type UpdateModuleInput = z.infer<typeof updateModuleSchema>;

// ── Response ────────────────────────────────────────────────────────────────

export const moduleResponseSchema = z.object({
	id: moduleIdSchema,
	milestoneId: milestoneIdSchema,
	name: z.string(),
	description: z.string().nullable(),
	status: z.enum(moduleStatusEnum),
	sortOrder: z.number().int()
});
export type ModuleResponse = z.infer<typeof moduleResponseSchema>;

import { z } from 'zod';
import { taskStatusEnum } from '../db/schema.js';
import { taskIdSchema, moduleIdSchema } from './common.js';

// ── Status transition map ───────────────────────────────────────────────────

const validTransitions: Record<string, string[]> = {
	todo: ['in-progress', 'skipped'],
	'in-progress': ['blocked', 'review', 'todo'],
	blocked: ['in-progress', 'todo'],
	review: ['done', 'in-progress'],
	done: [],
	skipped: []
};

export function isValidTransition(from: string, to: string): boolean {
	return validTransitions[from]?.includes(to) ?? false;
}

// ── Claim ───────────────────────────────────────────────────────────────────

export const claimTaskSchema = z.object({
	assignee: z.string().min(1, 'Assignee is required').max(100)
});
export type ClaimTaskInput = z.infer<typeof claimTaskSchema>;

// ── Progress update ─────────────────────────────────────────────────────────

export const progressTaskSchema = z.object({
	progressMessage: z.string().max(5000).optional(),
	subTotal: z.number().int().nonnegative().optional(),
	subDone: z.number().int().nonnegative().optional()
}).refine(
	(data) => {
		if (data.subTotal !== undefined && data.subDone !== undefined) {
			return data.subDone <= data.subTotal;
		}
		return true;
	},
	{ message: 'sub_done cannot exceed sub_total', path: ['subDone'] }
);
export type ProgressTaskInput = z.infer<typeof progressTaskSchema>;

// ── Complete ────────────────────────────────────────────────────────────────

export const completeTaskSchema = z.object({
	commitHash: z.string().max(40).optional(),
	progressMessage: z.string().max(5000).optional()
});
export type CompleteTaskInput = z.infer<typeof completeTaskSchema>;

// ── Admin action ────────────────────────────────────────────────────────────

export const adminTaskActionSchema = z.object({
	status: z.enum(taskStatusEnum),
	progressMessage: z.string().max(5000).optional()
});
export type AdminTaskActionInput = z.infer<typeof adminTaskActionSchema>;

// ── Response (with resolved references) ─────────────────────────────────────

export const taskResponseSchema = z.object({
	id: taskIdSchema,
	shortId: z.number().int().positive(),
	moduleId: moduleIdSchema,
	title: z.string(),
	description: z.string().nullable(),
	references: z.string().nullable(),
	status: z.enum(taskStatusEnum),
	assignee: z.string().nullable(),
	subTotal: z.number().int().nonnegative(),
	subDone: z.number().int().nonnegative(),
	progressMessage: z.string().nullable(),
	commitHash: z.string().nullable(),
	createdAt: z.string().datetime(),
	updatedAt: z.string().datetime(),
	reportedAt: z.string().datetime().nullable()
});
export type TaskResponse = z.infer<typeof taskResponseSchema>;

import { z } from 'zod';

// ── Pagination ──────────────────────────────────────────────────────────────

export const paginationQuerySchema = z.object({
	page: z.coerce.number().int().positive().default(1),
	perPage: z.coerce.number().int().positive().max(100).default(20)
});
export type PaginationQuery = z.infer<typeof paginationQuerySchema>;

export const paginatedResponseSchema = <T extends z.ZodTypeAny>(itemSchema: T) =>
	z.object({
		data: z.array(itemSchema),
		pagination: z.object({
			page: z.number().int().positive(),
			perPage: z.number().int().positive(),
			total: z.number().int().nonnegative(),
			totalPages: z.number().int().nonnegative()
		})
	});

// ── Error response ──────────────────────────────────────────────────────────

export const fieldErrorSchema = z.object({
	field: z.string(),
	message: z.string()
});
export type FieldError = z.infer<typeof fieldErrorSchema>;

export const errorResponseSchema = z.object({
	error: z.object({
		code: z.string(),
		message: z.string(),
		details: z.array(fieldErrorSchema).optional()
	})
});
export type ErrorResponse = z.infer<typeof errorResponseSchema>;

// ── ID formats ──────────────────────────────────────────────────────────────

export const milestoneIdSchema = z.string().regex(/^MS-\d+$/, 'Must match MS-{seq}');
export const moduleIdSchema = z.string().regex(/^MOD-\d+-\d+$/, 'Must match MOD-{ms_seq}-{seq}');
export const taskIdSchema = z.string().regex(/^TASK-\d+$/, 'Must match TASK-{seq}');

// ── Source markdown size limit (1 MB) ───────────────────────────────────────

export const SOURCE_MD_MAX_BYTES = 1_048_576;
export const sourceMdSchema = z
	.string()
	.max(SOURCE_MD_MAX_BYTES, `source_md must be under ${SOURCE_MD_MAX_BYTES} bytes`);

import { sveltekit } from '@sveltejs/kit/vite';
import tailwindcss from '@tailwindcss/vite';
import { defineConfig } from 'vite';

export default defineConfig({
	plugins: [tailwindcss(), sveltekit()]
});

import Database from 'better-sqlite3';
import { drizzle } from 'drizzle-orm/better-sqlite3';
import path from 'node:path';
import fs from 'node:fs';

const dbPath = process.env.DATABASE_PATH || path.join(process.cwd(), 'data', 'tracker.db');

// Ensure data directory exists
const dir = path.dirname(dbPath);
if (!fs.existsSync(dir)) {
	fs.mkdirSync(dir, { recursive: true });
}

const sqlite = new Database(dbPath);

// Enable WAL mode for concurrent read/write support
sqlite.pragma('journal_mode = WAL');
// Enable foreign key enforcement
sqlite.pragma('foreign_keys = ON');

export const db = drizzle(sqlite);
export default db;

import { describe, it, expect, beforeAll, afterAll, beforeEach } from 'vitest';
import Database from 'better-sqlite3';
import { drizzle } from 'drizzle-orm/better-sqlite3';
import { eq, and, desc } from 'drizzle-orm';
import * as schema from './schema.js';

// ── Test database setup ──────────────────────────────────────────────────────

let db: ReturnType<typeof drizzle>;
let sqliteDb: Database.Database;

const CREATE_TABLES_SQL = `
CREATE TABLE milestones (
  id TEXT PRIMARY KEY,
  title TEXT NOT NULL,
  source_md TEXT,
  git_url TEXT,
  status TEXT NOT NULL DEFAULT 'draft',
  created_at INTEGER NOT NULL DEFAULT (unixepoch())
);
CREATE INDEX milestone_status_idx ON milestones (status);

CREATE TABLE modules (
  id TEXT PRIMARY KEY,
  milestone_id TEXT NOT NULL REFERENCES milestones(id) ON DELETE CASCADE,
  name TEXT NOT NULL,
  description TEXT,
  status TEXT NOT NULL DEFAULT 'draft',
  sort_order INTEGER NOT NULL DEFAULT 0
);
CREATE INDEX module_milestone_id_idx ON modules (milestone_id);
CREATE INDEX module_status_idx ON modules (status);

CREATE TABLE tasks (
  id TEXT PRIMARY KEY,
  short_id INTEGER NOT NULL UNIQUE,
  module_id TEXT NOT NULL REFERENCES modules(id) ON DELETE CASCADE,
  title TEXT NOT NULL,
  description TEXT,
  "references" TEXT,
  status TEXT NOT NULL DEFAULT 'todo',
  assignee TEXT,
  sub_total INTEGER NOT NULL DEFAULT 0,
  sub_done INTEGER NOT NULL DEFAULT 0,
  progress_message TEXT,
  commit_hash TEXT,
  created_at INTEGER NOT NULL DEFAULT (unixepoch()),
  updated_at INTEGER NOT NULL DEFAULT (unixepoch()),
  reported_at INTEGER
);
CREATE INDEX task_status_module_idx ON tasks (status, module_id);
CREATE INDEX task_status_reported_idx ON tasks (status, reported_at);
CREATE INDEX task_module_id_idx ON tasks (module_id);
CREATE INDEX task_short_id_idx ON tasks (short_id);
`;

beforeAll(() => {
	sqliteDb = new Database(':memory:');
	sqliteDb.pragma('journal_mode = WAL');
	sqliteDb.pragma('foreign_keys = ON');
	sqliteDb.exec(CREATE_TABLES_SQL);
	db = drizzle(sqliteDb, { schema });
});

afterAll(() => {
	sqliteDb.close();
});

beforeEach(() => {
	sqliteDb.exec('DELETE FROM tasks');
